import "../css/Topbar.css";

function Topbar() {
  return (
    <header className="topbar">
      <h1 className="topbar-title">Kirana Store Owner Panel</h1>
      <span className="topbar-badge">Owner Use Only</span>
    </header>
  );
}

export default Topbar;
